// Demonstrating the non-blocking nature of Node.js I/O
const fs = require('fs');

console.log('1 — before read');

fs.readFile('/etc/hostname', 'utf8', (err, data) => {
  // This callback runs later, when the OS delivers the file contents
  if (err) throw err;
  console.log('3 — file contents:', data.trim());
});

console.log('2 — after read call (does not block)');

// Output is always in this order:
// 1 — before read
// 2 — after read call (does not block)
// 3 — file contents: my-hostname

// server.js — minimal HTTP server using only Node.js built-ins
const http = require('http');

const PORT = process.env.PORT || 3000;

const server = http.createServer((req, res) => {
  const url = new URL(req.url, `http://localhost:${PORT}`);

  if (url.pathname === '/' && req.method === 'GET') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ message: 'Hello from Node.js' }));
  } else {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Not found' }));
  }
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

