// async-file.js
const http = require('http');
const fs = require('fs/promises');  // Promise-based fs API (Node.js 14+)
const path = require('path');

const CONFIG_PATH = path.join(__dirname, 'config.json');

const server = http.createServer(async (req, res) => {
  if (req.url !== '/config') {
    res.writeHead(404).end(JSON.stringify({ error: 'Not found' }));
    return;
  }

  try {
    const raw = await fs.readFile(CONFIG_PATH, 'utf8');  // non-blocking
    const config = JSON.parse(raw);
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(config));
  } catch (err) {
    if (err.code === 'ENOENT') {
      res.writeHead(404).end(JSON.stringify({ error: 'config.json not found' }));
    } else {
      res.writeHead(500).end(JSON.stringify({ error: 'Internal server error' }));
    }
  }
});

server.listen(3000, () => console.log('Listening on :3000'));

// concurrent-fetch.js  (Node.js 18+ has built-in fetch)
async function fetchAll() {
  const t0 = Date.now();

  // All three HTTP requests begin immediately, without waiting for each other
  const [users, posts, comments] = await Promise.all([
    fetch('https://jsonplaceholder.typicode.com/users').then(r => r.json()),
    fetch('https://jsonplaceholder.typicode.com/posts').then(r => r.json()),
    fetch('https://jsonplaceholder.typicode.com/comments').then(r => r.json()),
  ]);

  console.log(`${users.length} users, ${posts.length} posts, ${comments.length} comments`);
  console.log(`Completed in ${Date.now() - t0}ms (concurrent, not sequential)`);
  // Typical output: Completed in ~380ms (vs ~1100ms if done serially)
}

fetchAll().catch(console.error);

// gateway.js  (Express + pg connection pool)
const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

// One connection pool shared by all requests — reuses TCP connections to Postgres
const db = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,                  // max simultaneous DB connections
  idleTimeoutMillis: 30_000,
});

// Fetch user profile + last 5 orders concurrently
app.get('/users/:id/summary', async (req, res) => {
  const { id } = req.params;

  try {
    const [userResult, ordersResult] = await Promise.all([
      db.query('SELECT id, name, email FROM users WHERE id = $1', [id]),
      db.query(
        'SELECT id, total, status FROM orders WHERE user_id = $1 ORDER BY created_at DESC LIMIT 5',
        [id]
      ),
    ]);

    if (userResult.rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json({
      user: userResult.rows[0],
      recentOrders: ordersResult.rows,
    });
  } catch (err) {
    console.error('DB error:', err.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

const PORT = process.env.PORT || 4000;
app.listen(PORT, () => console.log(`Gateway on :${PORT}`));

// ❌ readFileSync blocks the event loop — every other request waits
app.get('/data', (req, res) => {
  const raw = fs.readFileSync('/large-file.json');  // synchronous!
  res.json(JSON.parse(raw));
});

// ✅ readFile (Promise) is non-blocking — the event loop continues
app.get('/data', async (req, res) => {
  const raw = await fs.promises.readFile('/large-file.json');
  res.json(JSON.parse(raw));
});

// ❌ Unhandled rejection — crashes the process in Node.js 15+
async function loadUser(id) {
  return db.query('SELECT * FROM users WHERE id = $1', [id]);
}
loadUser(42);  // no .catch(), no try/catch around the await

// ✅ Handle rejections explicitly
try {
  const result = await loadUser(42);
  console.log(result.rows);
} catch (err) {
  console.error('Failed to load user:', err.message);
}

// ❌ Expensive synchronous computation blocks all other requests
app.post('/process', (req, res) => {
  const result = expensiveCpuTask(req.body.data);  // 500ms CPU work
  res.json({ result });
  // During those 500ms, no other request is handled
});

// ✅ Offload to a worker thread
const { Worker } = require('worker_threads');

app.post('/process', (req, res) => {
  const worker = new Worker('./cpu-worker.js', { workerData: req.body.data });
  worker.once('message', result => res.json({ result }));
  worker.once('error', err => res.status(500).json({ error: err.message }));
  // The event loop is free to handle other requests while the worker runs
});

// ❌ Two concurrent requests can interleave between read and write
let count = 0;
app.post('/increment', async (req, res) => {
  const current = count;          // Request A reads 5
  await delay(10);                // Request B also reads 5 here
  count = current + 1;            // Both write 6 — one increment is lost
  res.json({ count });
});

// ✅ Perform the mutation synchronously; do async work afterward
app.post('/increment', async (req, res) => {
  count += 1;                     // Atomic — no await between read and write
  await logToDatabase(count);     // Async work after the state is updated
  res.json({ count });
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received — shutting down');
  server.close(async () => {
    await db.end();      // drain connection pool
    process.exit(0);
  });
});

const cluster = require('cluster');
const os = require('os');
const http = require('http');

if (cluster.isPrimary) {
  const numCores = os.cpus().length;
  console.log(`Forking ${numCores} workers`);
  for (let i = 0; i < numCores; i++) cluster.fork();

  cluster.on('exit', (worker, code) => {
    console.log(`Worker ${worker.process.pid} exited (${code}) — restarting`);
    cluster.fork();
  });
} else {
  http.createServer((req, res) => {
    res.writeHead(200);
    res.end(`Handled by worker ${process.pid}\n`);
  }).listen(3000);
}

const helmet = require('helmet');  // sets ~15 security HTTP headers automatically
const express = require('express');
const app = express();

app.use(helmet());  // Content-Security-Policy, X-Frame-Options, etc.

// Redirect HTTP to HTTPS when behind a terminating proxy
app.use((req, res, next) => {
  if (req.headers['x-forwarded-proto'] !== 'https' && process.env.NODE_ENV === 'production') {
    return res.redirect(301, `https://${req.headers.host}${req.url}`);
  }
  next();
});
